{"code": "import json
import re

# Read funding data
funding_file = locals()['var_functions.query_db:0']
with open(funding_file, 'r') as f:
    funding_data = json.load(f)

# Create funding dictionary for lookup
funding_dict = {}
for record in funding_data:
    project_name = record.get('Project_Name', '')
    if project_name:
        funding_dict[project_name] = {
            'Funding_Source': record.get('Funding_Source', ''),
            'Amount': int(record.get('Amount', 0))
        }

# Read civic documents
civic_file = locals()['var_functions.query_db:18']
with open(civic_file, 'r') as f:
    civic_docs = json.load(f)

# Parse projects from civic documents
project_info = []

for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('
')

    current_category = None

    for line in lines:
        stripped = line.strip()

        # Detect section headers
        if 'Capital Improvement Projects (Design)' in stripped:
            current_category = ('capital', 'design')
        elif 'Capital Improvement Projects (Construction)' in stripped:
            current_category = ('capital', 'completed')
        elif 'Capital Improvement Projects (Not Started)' in stripped:
            current_category = ('capital', 'not started')
        elif 'Disaster Recovery Projects (Design)' in stripped:
            current_category = ('disaster', 'design')
        elif 'Disaster Recovery Projects (Construction)' in stripped:
            current_category = ('disaster', 'completed')
        elif 'Disaster Recovery Projects (Not Started)' in stripped:
            current_category = ('disaster', 'not started')

        # Look for project names (skip headers, metadata, and bullet points)
        elif current_category and stripped and not stripped.startswith(('\u2022', '(cid:', '\u25a0')):
            # Skip heading-like lines
            if any(phrase in stripped for phrase in ['RECOMMENDED ACTION', 'DISCUSSION', 'Project Description:', 'Project Updates:', 'Project Schedule:', 'Page', '\u2022', '(cid:']):
                continue

            # Skip very short lines or lines that look like descriptions
            if len(stripped) < 10 or stripped.startswith(('Updates:', 'Complete', 'Begin', 'Advertise:', 'Updates')):
                continue

            # Check if this is an emergency/FEMA related project
            lower_name = stripped.lower()
            if any(term in lower_name for term in ['fema', 'emergency', 'warning', 'siren', 'caloes', 'caljpia']):
                project_info.append({
                    'Project_Name': stripped,
                    'Type': current_category[0],
                    'Status': current_category[1],
                    'Topic': 'emergency, disaster, FEMA'
                })

# Merge with funding data
result = []
seen_projects = set()

for proj in project_info:
    proj_name = proj['Project_Name']
    if proj_name in funding_dict:
        key = proj_name
        funding_info = funding_dict[key]
        result_item = {
            'Project_Name': key,
            'Funding_Source': funding_info['Funding_Source'],
            'Amount': funding_info['Amount'],
            'Status': proj['Status'],
            'Topic': proj['Topic']
        }
        if key not in seen_projects:
            result.append(result_item)
            seen_projects.add(key)
    else:
        # Fuzzy match
        for fund_name, fund_info in funding_dict.items():
            if (proj_name in fund_name or fund_name in proj_name) and fund_name not in seen_projects:
                result.append({
                    'Project_Name': fund_name,
                    'Funding_Source': fund_info['Funding_Source'],
                    'Amount': fund_info['Amount'],
                    'Status': proj['Status'],
                    'Topic': proj['Topic']
                })
                seen_projects.add(fund_name)
                break

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

