import re

# Read funding data
funding_file = locals()['var_functions.query_db:0']
with open(funding_file, 'r') as f:
    funding_data = json.load(f)

# Create funding lookup dictionary
funding_dict = {}
for record in funding_data:
    project_name = record.get('Project_Name', '')
    if project_name:
        funding_dict[project_name] = {
            'Funding_Source': record.get('Funding_Source', ''),
            'Amount': int(record.get('Amount', 0))
        }

# Read civic documents
civic_file = locals()['var_functions.query_db:18']
with open(civic_file, 'r') as f:
    civic_docs = json.load(f)

# Extract emergency/FEMA project information
all_projects = []

for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')

    project_type = ''
    project_status = ''

    for line in lines:
        clean_line = line.strip()

        # Identify section headers
        if 'Capital Improvement Projects (Design)' in clean_line:
            project_type = 'capital'
            project_status = 'design'
        elif 'Capital Improvement Projects (Construction)' in clean_line:
            project_type = 'capital'
            project_status = 'completed'
        elif 'Capital Improvement Projects (Not Started)' in clean_line:
            project_type = 'capital'
            project_status = 'not started'
        elif 'Disaster Recovery Projects (Design)' in clean_line:
            project_type = 'disaster'
            project_status = 'design'
        elif 'Disaster Recovery Projects (Construction)' in clean_line:
            project_type = 'disaster'
            project_status = 'completed'
        elif 'Disaster Recovery Projects (Not Started)' in clean_line:
            project_type = 'disaster'
            project_status = 'not started'
        elif project_type and clean_line and len(clean_line) > 10:
            # Check for emergency/FEMA keywords
            lower_line = clean_line.lower()
            if any(term in lower_line for term in ['fema', 'emergency', 'warning', 'siren']):
                # Skip metadata lines
                if not any(skip in clean_line for skip in ['Updates:', 'Project Description', 'Project Updates', 'Project Schedule', 'RECOMMENDED ACTION', 'DISCUSSION', 'Page']):
                    all_projects.append({
                        'name': clean_line,
                        'type': project_type,
                        'status': project_status
                    })

# Build final result by matching with funding data
result = []
seen = set()

for proj in all_projects:
    proj_name = proj['name']

    # Direct match
    if proj_name in funding_dict:
        fund_data = funding_dict[proj_name]
        result.append({
            'Project_Name': proj_name,
            'Funding_Source': fund_data['Funding_Source'],
            'Amount': fund_data['Amount'],
            'Status': proj['status']
        })
        seen.add(proj_name)
    else:
        # Find closest match
        for fund_name in funding_dict:
            if fund_name in proj_name or proj_name in fund_name:
                if fund_name not in seen:
                    fund_data = funding_dict[fund_name]
                    result.append({
                        'Project_Name': fund_name,
                        'Funding_Source': fund_data['Funding_Source'],
                        'Amount': fund_data['Amount'],
                        'Status': proj['status']
                    })
                    seen.add(fund_name)
                break

# If no projects found directly in documents, use funding data with FEMA/emergency keywords
if not result:
    for proj_name, fund_data in funding_dict.items():
        if any(term in proj_name.lower() for term in ['fema', 'emergency', 'warning', 'siren', 'caloes', 'caljpia']):
            result.append({
                'Project_Name': proj_name,
                'Funding_Source': fund_data['Funding_Source'],
                'Amount': fund_data['Amount'],
                'Status': 'Unknown'
            })

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

